Send Email.code:
// Send a new email through Gmail.
// Pass a single message object, or an array to send several in one step.
sendMessage({
  // 1) Recipient address (or array of addresses).
  to: 'recipient@example.org',
  // 2) Subject line.
  subject: 'Hello from OpenFn',
  // 3) Message body. Plain text by default; pass html: true for HTML.
  body: `Hi there,\n\nThis email was sent from an OpenFn workflow.`,
  // 4) Optional CC / BCC.
  // cc: 'cc@example.org',
  // bcc: 'bcc@example.org',
  // 5) Optional file attachments.
  // attachments: [{ filename: 'report.csv', content: $.csv }],
});

Find Email.code:
// Find emails matching a Gmail search query.
// Results land on state.data as an array of message contents.
getContentsFromMessages({
  // 1) Standard Gmail search syntax (from:, subject:, after:, has:attachment, ...).
  query: 'from:billing@example.org subject:invoice after:2026/01/01',
  // 2) Which fields to pull back per message.
  contents: ['from', 'date', 'subject', 'body'],
  // 3) Cap the number of messages returned.
  maxResults: 25,
});
